# {The new algorithm focuses on visiting customers by evaluating the balance between the potential reduction in maximum fleet completion time and the clustering effect of the current visitation to optimize for early finishing.}
def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers):
    if len(unvisited_customers) == 0:
        return None

    num_trucks = len(all_truck_pos)
    completion_time_reduction = np.zeros(len(unvisited_customers))

    for idx, customer in enumerate(unvisited_customers):
        max_fleet_completion_time = 0
        for truck_pos in all_truck_pos:
            projected_completion_time = np.linalg.norm(truck_pos - customer) + np.linalg.norm(depot_pos - customer)
            if projected_completion_time > max_fleet_completion_time:
                max_fleet_completion_time = projected_completion_time

        distance_to_cur_truck = np.linalg.norm(cur_truck_pos - customer)
        clustering_effect = distance_to_cur_truck / (1 + max_fleet_completion_time)
        completion_time_reduction[idx] = clustering_effect

    best_node = np.argmin(completion_time_reduction)
    return best_node
